export type EmbedBridgeEvent =
  | { type: "streamflow:joined"; payload: { roomId?: string; streamId?: string; participantId?: string } }
  | { type: "streamflow:left"; payload: { reason?: string } }
  | { type: "streamflow:error"; payload: { code?: string; message: string } }

export function postEmbedEvent(event: EmbedBridgeEvent, targetOrigin = "*") {
  if (typeof window === "undefined" || window.parent === window) return
  window.parent.postMessage(event, targetOrigin)
}

export function isEmbedBridgeEvent(data: unknown): data is EmbedBridgeEvent {
  if (!data || typeof data !== "object") return false
  const type = (data as { type?: unknown }).type
  return (
    type === "streamflow:joined" ||
    type === "streamflow:left" ||
    type === "streamflow:error"
  )
}
